	&lt;li&gt;&amp;quot;&lt;span style=&quot;font-weight: 700;&quot;&gt;Bhopal (capital of Madhya Pradesh&lt;/span&gt;)&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;rdquo;&amp;nbsp;&lt;/span&gt;and&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;ldquo;Gandhinagar (capital of Gujarat)&amp;rdquo;&amp;nbsp;&lt;/span&gt;is also located&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;fairly close to the &amp;ldquo;Tropic of Cancer&amp;rdquo;.&amp;nbsp;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
